import{_ as t,o as a,c as o,ae as s}from"./chunks/framework.BtCEPByy.js";const u=JSON.parse('{"title":"Run Your First Task","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md"}'),i={name:"guide/usage.md"};function r(l,e,n,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="run-your-first-task" tabindex="-1">Run Your First Task <a class="header-anchor" href="#run-your-first-task" aria-label="Permalink to &quot;Run Your First Task&quot;">​</a></h1><p>Once a runner is online, Flowy follows a simple loop: create a task, assign it, watch it run, and review the result.</p><h2 id="step-1-open-a-project-or-use-inbox" tabindex="-1">Step 1: Open a project or use Inbox <a class="header-anchor" href="#step-1-open-a-project-or-use-inbox" aria-label="Permalink to &quot;Step 1: Open a project or use Inbox&quot;">​</a></h2><p>You can work in either place:</p><ul><li><code>Projects</code> keeps related work together.</li><li><code>Inbox</code> shows active tasks across every project.</li></ul><p>For a first run, opening a project is usually the clearest path.</p><h2 id="step-2-create-a-task" tabindex="-1">Step 2: Create a task <a class="header-anchor" href="#step-2-create-a-task" aria-label="Permalink to &quot;Step 2: Create a task&quot;">​</a></h2><ol><li>Click <code>New Task</code>.</li><li>Enter a short, direct title.</li><li>Use the description for context, constraints, or the expected outcome.</li><li>Set priority and labels if they help with triage.</li><li>Click <code>Create task</code>.</li></ol><p>Good tasks usually include the goal, the repo or workspace involved, and any limits the AI should respect.</p><h2 id="step-3-assign-the-task" tabindex="-1">Step 3: Assign the task <a class="header-anchor" href="#step-3-assign-the-task" aria-label="Permalink to &quot;Step 3: Assign the task&quot;">​</a></h2><p>Open the task, then click <code>Assign task</code> or <code>Reassign</code>.</p><p>In the assignment dialog:</p><ol><li>Choose a runner.</li><li>Choose an AI provider from the list that runner advertises.</li><li>Fill in the harness settings you want to pass through.</li><li>Click <code>Assign task</code>.</li></ol><p>If a provider is missing, that runner does not currently detect the matching CLI.</p><h2 id="step-4-set-the-right-harness-values" tabindex="-1">Step 4: Set the right harness values <a class="header-anchor" href="#step-4-set-the-right-harness-values" aria-label="Permalink to &quot;Step 4: Set the right harness values&quot;">​</a></h2><p>The most important field is usually <code>workspace</code>.</p><ul><li>Set <code>workspace</code> to a path that exists on the runner machine.</li><li>Set <code>model</code> only if you want to force a specific model.</li><li>Set <code>sandbox</code>, <code>mode</code>, or <code>worktree</code> only when the selected CLI needs them.</li></ul><p>You do not need to fill every field. Flowy works well when you keep the config as small as possible.</p><h2 id="step-5-watch-execution" tabindex="-1">Step 5: Watch execution <a class="header-anchor" href="#step-5-watch-execution" aria-label="Permalink to &quot;Step 5: Watch execution&quot;">​</a></h2><p>After assignment:</p><ol><li>The task is queued on the selected runner.</li><li>The runner picks it up and changes the task to <code>in_progress</code>.</li><li>Output streams back into Flowy while the CLI runs.</li><li>The runner status changes to <code>busy</code>.</li><li>When the command exits, the task becomes <code>done</code> or <code>failed</code>.</li></ol><p>The <code>Inbox</code> view is useful when you want to monitor active work across multiple projects at once.</p><h2 id="step-6-review-the-result" tabindex="-1">Step 6: Review the result <a class="header-anchor" href="#step-6-review-the-result" aria-label="Permalink to &quot;Step 6: Review the result&quot;">​</a></h2><p>Open the task detail view to inspect:</p><ul><li>streamed output</li><li>assigned runner</li><li>selected provider</li><li>harness summary badges</li><li>final status</li></ul><p>If a task fails, you can update the task details and assign it again to the same runner or a different one.</p><h2 id="a-simple-working-pattern" tabindex="-1">A simple working pattern <a class="header-anchor" href="#a-simple-working-pattern" aria-label="Permalink to &quot;A simple working pattern&quot;">​</a></h2><p>Many teams settle into this sequence:</p><ol><li>Create a project for a repo or workstream.</li><li>Add focused tasks with clear titles.</li><li>Route each task to the machine that has the right CLI and workspace.</li><li>Use <code>Inbox</code> to watch active work.</li><li>Move completed tasks to <code>done</code> and retry failures with better context.</li></ol><p>For help choosing runners, providers, and assignment fields, continue to <a href="/Flowy/guide/developer-reference">Runner &amp; Provider Guide</a>.</p>',30)])])}const k=t(i,[["render",r]]);export{u as __pageData,k as default};
